mapper.select:
SELECT sessionId, sellerId, buyerId, postId,
       createTime, lastMessageTime, isArchived, messageList
FROM chatSession
WHERE buyerId   = #{buyerId}
  AND sellerId  = #{sellerId}
  AND postId    = #{postId}
  AND isArchived = false
LIMIT 1

mapper.insert:
INSERT INTO chatSession (
    sessionId, sellerId, buyerId, postId,
    createTime, lastMessageTime, isArchived, messageList
) VALUES (
    #{sessionId}, #{sellerId}, #{buyerId}, #{postId},
    #{createTime}, #{lastMessageTime}, #{isArchived},
    #{messageList, typeHandler=org.example.boilercommon.JsonListTypeHandler}
)

mapper.update:
UPDATE chatSession
SET messageList      = #{messageList, typeHandler=org.example.boilercommon.JsonListTypeHandler},
    lastMessageTime = #{lastMessageTime}
WHERE sessionId = #{sessionId}
